 1	import * as React from 'react';
 2	import { Label, pluralize } from '@patternfly/react-core';
 3	
 4	import { PFColors } from 'components/Pf/PfColors';
 5	import { Span } from 'types/TracingInfo';
 6	import { isErrorTag } from 'utils/tracing/TracingHelper';
 7	import { kialiStyle } from 'styles/StyleUtils';
 8	
 9	/**
10	 * PF4 adds a wrapper for the label content
11	 * And the label color is override by .pf-v5-c-label__content
12	 * And there are not styles with the color white
13	 */
14	const whiteLabelStyle = kialiStyle({
15	  $nest: {
16	    '& > .pf-v6-c-label__content': {
17	      color: PFColors.Color100
18	    }
19	  }
20	});
21	
22	type Props = {
23	  spans: Span[];
24	  filteredSpans?: Span[];
25	  oneline: boolean;
26	};
27	
28	const countServices = (spans: Span[]) => {
29	  const services = new Set();
30	  spans.forEach(s => services.add(s.process.serviceName));
31	  return services.size;
32	};
33	
34	const countErrors = (spans: Span[]) => {
35	  return spans.filter(sp => sp.tags.some(isErrorTag)).length;
36	};
37	
38	export const TraceLabels = (p: Props) => {
39	  const errors = countErrors(p.spans);
40	  const filteredErrors = p.filteredSpans ? countErrors(p.filteredSpans) : undefined;
41	  return (
42	    <>
43	      <Label style={{ margin: 10 }} color="blue">
44	        {p.filteredSpans && `${p.filteredSpans.length} / `}
45	        {pluralize(p.spans.length, 'Span')}
46	      </Label>
47	      <Label style={{ margin: 10 }} color="blue">
48	        {p.filteredSpans && `${countServices(p.filteredSpans)} / `}
49	        {pluralize(countServices(p.spans), 'App')} involved
50	      </Label>
51	      {!p.oneline && <br />}
52	      {errors === 0 ? (
53	        <Label className={whiteLabelStyle} style={{ margin: 10, backgroundColor: PFColors.Success }}>
54	          0 Spans with error
55	        </Label>
56	      ) : (
57	        <Label
58	          className={whiteLabelStyle}
59	          style={{ margin: 10, backgroundColor: filteredErrors === 0 ? PFColors.Warning : PFColors.Danger }}
60	        >
61	          {p.filteredSpans && `${filteredErrors} / `}
62	          {pluralize(errors, 'Span')} with error
63	        </Label>
64	      )}
65	    </>
66	  );
67	};

